mapper.select:
select YYYY, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, MODEL, SPEC, INCH, GLASS_THICK, SHEET, BLOCK, CELL, RUN_SIZE, X, Y, XY from DOI_MODEL_MAST where 1=1
and yyyy = #{yyyy}
and site = #{site}
order BY MODEL;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
YYYY varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
SITE varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
MODEL varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
SPEC varchar(76) COLLATE Korean_Wansung_CI_AS NOT NULL,
INCH real NULL,
GLASS_THICK real NULL,
SHEET real NULL,
BLOCK real NULL,
CELL real NULL,
RUN_SIZE real NULL,
X real NULL,
Y real NULL,
XY real NULL
);

INSERT INTO #TempTable1
(
YYYY
, SEL_CODE
, SITE
, MODEL
, SPEC
, INCH
, GLASS_THICK
, SHEET
, BLOCK
, CELL
, RUN_SIZE
, X
, Y
, XY
)
VALUES

	(
	#{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	, #{item.field13}
	, #{item.field14}
	, #{item.field15}
	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_MODEL_MAST b
	WHERE 1=1
	AND b.YYYY = a.YYYY
	AND b.SITE = a.SITE
	AND b.MODEL = a.MODEL
);

mapper.insert:
CREATE TABLE #TempTable (
	seq_no INT,
	YYYY varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	MODEL varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SPEC varchar(76) COLLATE Korean_Wansung_CI_AS NOT NULL,
	INCH real NULL,
	GLASS_THICK real NULL,
	SHEET real NULL,
	BLOCK real NULL,
	CELL real NULL,
	RUN_SIZE real NULL,
	X real NULL,
	Y real NULL,
	XY real NULL
);

INSERT INTO #TempTable
(
seq_no
, YYYY
, SEL_CODE
, SITE
, MODEL
, SPEC
, INCH
, GLASS_THICK
, SHEET
, BLOCK
, CELL
, RUN_SIZE
, X
, Y
, XY
)
VALUES

	(
	#{item.field1}
	, #{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	, #{item.field13}
	, #{item.field14}
	, #{item.field15}
	)
;

INSERT INTO DOI_MODEL_MAST (YYYY, SEL_CODE, SITE, MODEL, SPEC, INCH, GLASS_THICK, SHEET, BLOCK, CELL, RUN_SIZE, X, Y, XY)
SELECT YYYY, SEL_CODE, SITE, MODEL, SPEC, INCH, GLASS_THICK, SHEET, BLOCK, CELL, RUN_SIZE, X, Y, XY
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYY, SITE, MODEL) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_MODEL_MAST b
	WHERE 1=1
	AND b.YYYY = a.YYYY
	AND b.SITE = a.SITE
	AND b.MODEL = a.MODEL
);

DROP TABLE #TempTable;

INSERT INTO DOI_MODEL_MAST
(
YYYY
, SEL_CODE
, SITE
, MODEL
, SPEC
, INCH real
, GLASS_THICK
, SHEET
, BLOCK
, CELL
, RUN_SIZE
, X
, Y
, XY
)
VALUES
(
#{yyyy}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{model}
, #{spec}
, #{inch}
, #{glassThick}
, #{sheet}
, #{block}
, #{cell}
, #{runSize}
, #{x}
, #{y}
, #{xy}
);

mapper.delete:
DELETE FROM DOI_MODEL_MAST
WHERE 1=1
and yyyy = #{yyyy}
and sel_code = #{selCode}
and site = #{siteOrg}
and model = #{model}

mapper.update:
